            let NdotV = max(dot(N, V), 0.0);
            let NdotL = max(dot(N, L), 0.0);

            let denominator = 4.0 * NdotV * NdotL + 0.0001;
            let specular = numerator / denominator;

            let kS = F;
            var kD = vec3f(1.0) - kS;
            kD *= 1.0 - metallic;

