    this.planes[2].setComponents(me3 + me1, me7 + me5, me11 + me9, me15 + me13);
    this.planes[3].setComponents(me3 - me1, me7 - me5, me11 - me9, me15 - me13);
    this.planes[4].setComponents(me3 + me2, me7 + me6, me11 + me10, me15 + me14);
