    let u = f * f * f * (f * (f * 6.0 - 15.0) + 10.0);

    // Get gradients at four corners
    let g00 = gradient2D(i + vec2f(0.0, 0.0));
    let g10 = gradient2D(i + vec2f(1.0, 0.0));
