  width: 256,
  height: 256,
  bladeCount: 12,
  baseColor: { r: 0.15, g: 0.35, b: 0.08 },
  tipColor: { r: 0.3, g: 0.55, b: 0.15 },
  colorVariation: 0.15,
  bladeWidth: 8,
  curvature: 0.4,
  seed: 12345,
  noisy: true
