        let edgeV = abs(-2.0 * lumaN + lumaNW + lumaNE) +
                    abs(-2.0 * lumaM + lumaW + lumaE) * 2.0 +
                    abs(-2.0 * lumaS + lumaSW + lumaSE);

        let isHorizontal = edgeH >= edgeV;

        // Choose edge direction
        var stepLength: f32;
        var luma1: f32;
        var luma2: f32;

        if (isHorizontal) {
          stepLength = invSize.y;
          luma1 = lumaN;
          luma2 = lumaS;
        } else {
          stepLength = invSize.x;
          luma1 = lumaW;
          luma2 = lumaE;
        }

