        intensity: f32,
        decay: f32,
        density: f32,
        weight: f32,
        exposure: f32,
        numSamples: f32,
        lightColor: vec3f,
        offScreenFalloff: f32,      // Intensity falloff for off-screen light
        resolution: vec2f,
        maxDistance: f32,
        isOnScreen: f32,
        clampedLightPos: vec2f,     // Light position clamped to screen edge
        _pad: vec2f,
