function packBVHNodes(nodes) {
  const packed = new Float32Array(nodes.length * 8);
  const view = new DataView(packed.buffer);
  for (let i = 0;i < nodes.length; i++) {
    const node = nodes[i];
    const offset = i * 8;
    packed[offset + 0] = node.minX;
    packed[offset + 1] = node.minY;
    packed[offset + 2] = node.minZ;
    view.setUint32((offset + 3) * 4, node.leftOrFirst, true);
    packed[offset + 4] = node.maxX;
    packed[offset + 5] = node.maxY;
    packed[offset + 6] = node.maxZ;
    view.setUint32((offset + 7) * 4, node.rightOrCount, true);
  }
  return packed;
}
