    const uv1 = uvs.length > 0 ? [uvs[i1 * 2 + 0] || 0, uvs[i1 * 2 + 1] || 0] : [0, 0];
    const uv2 = uvs.length > 0 ? [uvs[i2 * 2 + 0] || 0, uvs[i2 * 2 + 1] || 0] : [0, 0];
