    nodes: packedNodes,
    triangles: packedTriangles,
    trianglesWithUV: packedTrianglesWithUV,
    materials: packedMaterials,
    nodeCount: nodes.length,
    triangleCount: orderedTriangles.length,
    materialCount: materials.length,
